%[text] # 例1.12（圧縮処理）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
isVerbose = false;
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example01_12"; % mfilename

imgname = "msipimg05";
imgfmt = "tiff";
%%
%[text] ## 画像データの読込
imgfile = fullfile(datfolder,imgname);
V = imresize(rgb2gray(imread(imgfile,imgfmt)),[96 96],'bilinear');
%%
%[text] ## 圧縮前のデータ量
dataInfo = whos('V');
fprintf('圧縮前のバイト数： %d bytes\n',dataInfo.bytes) %[output:2c3215c9]
fprintf('圧縮前のビット数： %6.2f bpp\n',8*dataInfo.bytes/prod(dataInfo.size)) %[output:7d49c13e]
%%
%[text] ## 圧縮前の画像表示
figure(1) %[output:5e5213dd]
imshow(V) %[output:5e5213dd]
title('原画像') %[output:5e5213dd]
%%
%[text] ## JPEG圧縮
qFactor = 13; % 品質制御 [0,100]
resimg = fullfile(resfolder,myfilename+"_"+imgname);
resfmt = "jpg";
imwrite(V,resimg+"."+resfmt,'Quality',qFactor)
%%
%[text] ## 圧縮後のデータ量
fileInfo = dir(resimg+"."+resfmt) %[output:8b48f50c]
fprintf('圧縮後のバイト数： %d bytes\n',fileInfo.bytes) %[output:3a29c982]
fprintf('圧縮後のビット数： %6.2f bpp\n',8*fileInfo.bytes/prod(dataInfo.size)) %[output:58c68b51]
%%
%[text] ## 圧縮後の画像表示
U = imread(resimg,resfmt);
figure(2) %[output:38c3f270]
imshow(U) %[output:38c3f270]
title('JPEG圧縮画像') %[output:38c3f270]
%%
%[text] ## 圧縮前後の差分画像表示
Y = imadjust(imabsdiff(U,V));
figure(3) %[output:5395cad6]
imshow(Y) %[output:5395cad6]
title('差分画像') %[output:5395cad6]
%%
%[text] ## ピーク信号対雑音比による誤差評価
fprintf('PSNR:  %6.2f dB\n',psnr(V,U)) %[output:0c054bf0]
%%
%[text] ## 結果出力
imwrite(V,fullfile(resfolder,"fig01-03a.png"))
imwrite(U,fullfile(resfolder,"fig01-03b.jpg"))
imwrite(Y,fullfile(resfolder,"fig01-03c.png"))
%%
